helper_functions.MACD_line:
def MACD_line(values, fast=12, slow=26):
    """MACD line"""
    return EMA(values, fast) - EMA(values, slow)

helper_functions.MACD_signal:
def MACD_signal(values, fast=12, slow=26, signal=9):
    """MACD signal line"""
    macd = MACD_line(values, fast, slow)
    return EMA(macd, signal)

helper_functions.VWAP:
def VWAP(high, low, close, volume):
    """Volume Weighted Average Price"""
    typical_price = (np.asarray(high) + np.asarray(low) + np.asarray(close)) / 3
    return np.cumsum(typical_price * volume) / (np.cumsum(volume) + 1e-10)

helper_functions.ParabolicSAR:
def ParabolicSAR(high, low, close, step=0.02, maximum=0.2):
    """Parabolic SAR"""
    high = np.asarray(high, dtype=float)
    low = np.asarray(low, dtype=float)
    n = len(close)
    sar = np.zeros(n)
    trend = 1
    af = step
    ep = high[0]
    sar[0] = low[0]
    for i in range(1, n):
        sar[i] = sar[i-1] + af * (ep - sar[i-1])
        if trend == 1:
            if low[i] < sar[i]:
                trend = -1
                sar[i] = ep
                ep = low[i]
                af = step
            else:
                if high[i] > ep:
                    ep = high[i]
                    af = min(af + step, maximum)
        else:
            if high[i] > sar[i]:
                trend = 1
                sar[i] = ep
                ep = high[i]
                af = step
            else:
                if low[i] < ep:
                    ep = low[i]
                    af = min(af + step, maximum)
    return sar

helper_functions.OBV:
def OBV(close, volume):
    """On Balance Volume"""
    close = np.asarray(close, dtype=float)
    volume = np.asarray(volume, dtype=float)
    obv = np.zeros_like(close)
    obv[0] = volume[0]
    for i in range(1, len(close)):
        if close[i] > close[i-1]:
            obv[i] = obv[i-1] + volume[i]
        elif close[i] < close[i-1]:
            obv[i] = obv[i-1] - volume[i]
        else:
            obv[i] = obv[i-1]
    return obv

helper_functions.VIDYA:
def VIDYA(values, period=14, cmo_period=9):
    """Variable Index Dynamic Average"""
    values = np.asarray(values, dtype=float)
    result = np.zeros_like(values)
    result[0] = values[0]
    for i in range(1, len(values)):
        if i < cmo_period:
            cmo = 0
        else:
            ups = 0
            downs = 0
            for j in range(i - cmo_period + 1, i + 1):
                change = values[j] - values[j-1]
                if change > 0:
                    ups += change
                else:
                    downs -= change
            cmo = abs(ups - downs) / (ups + downs + 1e-10)
        sc = 2 / (period + 1)
        result[i] = sc * cmo * values[i] + (1 - sc * cmo) * result[i-1]
    return result

helper_functions.Ichimoku_Kijun:
def Ichimoku_Kijun(high, low, period=26):
    """Ichimoku Kijun-sen"""
