    return Ichimoku_Tenkan(high, low, period)

helper_functions.TRIX:
def TRIX(values, period=14):
    """Triple Exponential Average"""
    ema1 = EMA(values, period)
    ema2 = EMA(ema1, period)
    ema3 = EMA(ema2, period)
    trix = np.zeros_like(ema3)
    for i in range(1, len(ema3)):
        if ema3[i-1] != 0:
            trix[i] = (ema3[i] - ema3[i-1]) / ema3[i-1] * 100
    return trix

helper_functions.ForceIndex:
def ForceIndex(close, volume, period=13):
    """Force Index"""
    close = np.asarray(close, dtype=float)
    volume = np.asarray(volume, dtype=float)
    force = np.zeros_like(close)
    for i in range(1, len(close)):
        force[i] = (close[i] - close[i-1]) * volume[i]
    return EMA(force, period)

helper_functions.AwesomeOsc:
def AwesomeOsc(high, low, fast=5, slow=34):
    """Awesome Oscillator"""
    hl2 = (np.asarray(high) + np.asarray(low)) / 2
    fast_sma = np.zeros_like(hl2)
    slow_sma = np.zeros_like(hl2)
    for i in range(fast - 1, len(hl2)):
        fast_sma[i] = np.mean(hl2[i - fast + 1:i + 1])
    for i in range(slow - 1, len(hl2)):
        slow_sma[i] = np.mean(hl2[i - slow + 1:i + 1])
    return fast_sma - slow_sma
